{
  "competency_groups": [
    {
      "code": "PHX12-U1-C01",
      "title": "Electric Charges and Fields Competencies",
      "description": "Mastering fundamental electrostatic principles including charge conservation, Coulomb's law, electric fields from various distributions, dipole behavior, and Gauss's theorem applications.",
      "competencies": [
        "Apply superposition principle to calculate net force on charges in a system."
      ],
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Electric Charges and Fields"
    },
    {
      "code": "PHX12-U1-C02",
      "title": "Electrostatic Potential and Capacitance Competencies",
      "description": "Understanding electric potential, equipotential surfaces, energy storage in capacitors, and the behavior of dielectrics.",
      "competencies": [
        "Analyze series and parallel combinations of capacitors to determine equivalent capacitance."
      ],
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Electrostatic Potential and Capacitance"
    },
    {
      "code": "PHX12-U2-C03",
      "title": "Current Electricity Competencies",
      "description": "Exploring the flow of electric current, resistance characteristics, Ohm's law applications, and circuit analysis using Kirchhoff's rules.",
      "competencies": [
        "Utilize Kirchhoff's laws to solve complex electrical circuits."
      ],
      "unit_name": "Unit-II Current Electricity",
      "chapter_name": "Current Electricity"
    },
    {
      "code": "PHX12-U3-C04",
      "title": "Moving Charges and Magnetism Competencies",
      "description": "Investigating the magnetic effects of electric currents, forces on moving charges, and the operation of measuring instruments like galvanometers.",
      "competencies": [
        "Calculate force exerted by a uniform magnetic field on current-carrying conductors."
      ],
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Moving Charges and Magnetism"
    },
    {
      "code": "PHX12-U3-C05",
      "title": "Magnetism and Matter Competencies",
      "description": "Examining the properties of magnetic materials, magnetization concepts, and the equivalence between bar magnets and solenoids.",
      "competencies": [
        "Differentiate between paramagnetic, diamagnetic, and ferromagnetic behaviors qualitatively."
      ],
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Magnetism and Matter"
    }
  ]
}
